'library(ggplot2)

dataset_top <- head(dataset[order(-dataset[,1]),], 8)
dataset_top$order_lines <- dataset_top[,1]
dataset_top$order_lines_py <- dataset_top[,2]
dataset_top$account <- dataset_top[,3]
dataset_top$account <- factor(dataset_top$account, levels=rev(dataset_top$account))
dataset_top$pct_change <- (dataset_top$order_lines - dataset_top$order_lines_py) / dataset_top$order_lines_py
dataset_top$arrow <- ifelse(dataset_top$pct_change > 0, "\u25B2", "\u25BC")
dataset_top$label_color <- ifelse(dataset_top$pct_change > 0, "#1971c2", "#c2255c")

format_thousands <- function(val) {
  if (val >= 100000) {
    return(paste0(round(val/1000), "K"))
  } else if (val >= 10000) {
    return(paste0(sprintf("%.1f", val/1000), "K"))
  } else {
    return(paste0(sprintf("%.2f", val/1000), "K"))
  }
}

dataset_top$data_label <- paste0(sapply(dataset_top$order_lines, format_thousands), " (", dataset_top$arrow, sprintf("%.0f%%", abs(dataset_top$pct_change)*100), ")")

max_val <- max(dataset_top$order_lines, na.rm=TRUE)
x_range <- c(-max_val * 0.35, max_val * 1.18)

p <- ggplot(dataset_top, aes(x=order_lines, y=account)) +
  geom_col(fill="#7FA9C7", alpha=0.65, width=0.65) +
  geom_segment(aes(x=order_lines_py, xend=order_lines_py, y=as.numeric(account)-0.4, yend=as.numeric(account)+0.4), color="#6C757D", size=1.5, lineend="round") +
  geom_text(aes(label=data_label, color=label_color), hjust=-0.05, size=4, fontface="bold", show.legend=FALSE) +
  scale_color_identity() +
  scale_x_continuous(labels=function(x) ifelse(x >= 0, paste0(round(x/1000),"K"), ""), limits=x_range, expand=c(0,0)) +
  scale_y_discrete() +
  coord_cartesian(clip="off") +
  theme_minimal(base_size=12) +
  theme(
    panel.grid=element_blank(),
    axis.title.x=element_text(color="#495057", size=11),
    axis.title.y=element_blank(),
    axis.text.x=element_text(color="#6C757D", size=10),
    axis.text.y=element_blank(),
    axis.ticks.y=element_blank(),
    plot.margin=margin(t=5, r=5, b=5, l=5, unit="pt")
  ) +
  labs(x="Order Lines")

for(i in 1:nrow(dataset_top)) {
  y_pos <- nrow(dataset_top) - i + 1
  label_col <- dataset_top$label_color[i]
  p <- p + annotate("text", x=-max_val * 0.02, y=y_pos, label=dataset_top$account[i], hjust=1, size=4.5, fontface="bold", color=label_col, family="Segoe UI Semibold")
}

print(p)'
